/* oms-orderrest-sql-oracle.xml  insertInterfaceObHdList */
INSERT INTO TORDER_INTF_OBORDER_HD
(
	  EXTORDERTYPECD
    , ORGORDERKEY
    , CLAIMNO
	, DLVYMETHDCD
	, DLVYMETHDDTCD
	, CTKEY
	, MALORDERDIV
	, NISCNLRNGDIV
	, DLVYEXPCTDAY
	, ORDERISTDAY
	, PAYMTCOMPLDAY
	, BUYER
	, BUYERTEL01
	, BUYERTEL02
	, BUYERZIPCD
	, BUYERADDRHD
	, BUYERADDRDT
	, RECPNM
	, RECPTEL01
	, RECPTEL02
	, RECPZIPCD
	, RECPADDRHD
	, RECPADDRDT
	, CMT
	, PARTERID
	, ACCESSKEY
	, ADDCMT01
	, ADDCMT02
	, ADDCMT03
	, REQUESTDT
	, IFID
	, INSERTDATE
	, INSERTURKEY
	, UPDATEDATE
	, UPDATEURKEY
) VALUES (
	  #{extordertypecd}
	, #{orgorderkey}
	, #{claimno}
	, #{dlvymethdcd}
	, #{dlvymethddtcd}
	, CASE WHEN #{extordertypecd} = #{excextordertypecd} 
		   THEN (
			     SELECT MAX(X.CTKEY) 
		   		 FROM TORDER_INFO_CO_HD X 
		   		 WHERE X.ORGORDERKEY = #{orgorderkey} 
		   		 AND X.EXTORDERTYPECD = #{orgextordertypecd}
		   		 ) 
	  ELSE COALESCE(#{ctkey}, '09')
	  END
	, #{malorderdiv}
	, #{niscnlrngdiv}
	, #{dlvyexpctday}
	, #{orderistday}
	, #{paymtcomplday}
	, #{buyer}
	, #{buyertel01}
	, #{buyertel02}
	, #{buyerzipcd}
	, #{buyeraddrhd}
	, #{buyeraddrdt}
	, #{recpnm}
	, #{recptel01}
	, #{recptel02}
	, #{recpzipcd}
	, #{recpaddrhd}
	, #{recpaddrdt}
	, #{cmt}
	, #{parterid}
	, #{accesskey}
	, #{addcmt01}
	, #{addcmt02}
	, #{addcmt03}
	, #{requestDt}
	, #{interfaceId}
	, #{interfaceDate}
	, #{interfaceUrkey}
	, #{interfaceDate}
	, #{interfaceUrkey}
)

