/* oms-orderrest-sql-oracle.xml updateNisSoHd */
UPDATE TORDER_INFO_SO_HD 
   SET WKSTATUS = CASE WHEN #{compyn}='Y' THEN #{socompstatus} ELSE WKSTATUS END
	 , NISSNDYN = CASE WHEN  #{compyn}='Y' THEN #{nissndyn} ELSE NISSNDYN END
  	 , NISYN = COALESCE(#{nisyn}, 'Y')
  	 , NISCNLRNGDIV = #{niscnlrngdiv}
     , UPDATEDATE = #{interfaceDate}
     , UPDATEURKEY = #{interfaceUrkey}
 WHERE OWKEY = #{owkey}
   AND SOHDKEY = #{sohdkey}

/* oms-orderrest-sql-oracle.xml updateNisCoDt */
UPDATE TORDER_INFO_CO_DT 
   SET WKSTATUS = #{cowkstatus}
     , UPDATEDATE = #{interfaceDate}
     , UPDATEURKEY = #{interfaceUrkey}
 WHERE OWKEY = #{owkey}
   AND COHDKEY = #{cohdkey}
   AND CODTKEY = #{codtkey}

/* oms-orderrest-sql-oracle.xml updateNisCoHd */
UPDATE TORDER_INFO_CO_HD 
   SET WKSTATUS = #{cowkstatus}
     , UPDATEDATE = #{interfaceDate}
     , UPDATEURKEY = #{interfaceUrkey}
 WHERE OWKEY = #{owkey}
   AND COHDKEY = #{cohdkey}

		/* oms-orderrest-sql-oracle.xml updateCoHdAfterEo */
		UPDATE TORDER_INFO_CO_HD 
		   SET WKSTATUS = COALESCE(#{coWkstatus}, WKSTATUS)
             , UPDATEDATE = #{updatedate}
             , UPDATEURKEY = #{updateurkey}
		 WHERE OWKEY = #{owkey}
		   AND COHDKEY = #{cohdkey}
		   AND COHDKEY IN (SELECT MAX(COHDKEY)
		   					 FROM TORDER_INFO_SO_DT
		   					WHERE OWKEY = #{owkey}
							  AND SOHDKEY = #{sohdkey}
							  AND COALESCE(NISYN, 'N') != 'Y'
		   				   )

		/* oms-orderrest-sql-oracle.xml updateCoDtAfterEo */
		UPDATE TORDER_INFO_CO_DT 
		   SET WKSTATUS = COALESCE(#{coWkstatus}, WKSTATUS)
             , UPDATEDATE = #{updatedate}
             , UPDATEURKEY = #{updateurkey}
		 WHERE OWKEY = #{owkey}
		   AND COHDKEY = #{cohdkey}
		   AND CODTKEY IN (SELECT CODTKEY
		   					 FROM TORDER_INFO_SO_DT
		   					WHERE OWKEY = #{owkey}
							  AND SOHDKEY = #{sohdkey}
							  AND COALESCE(NISYN, 'N') != 'Y'
		   				   )

		/* oms-orderrest-sql-oracle.xml updateSoHdAfterEo */
		UPDATE TORDER_INFO_SO_HD 
		   SET WKSTATUS = #{wkstatus}
		     , ORDERSNDYN = CASE WHEN #{wkstatus}=#{sendWkstatus} THEN 'Y' ELSE ORDERSNDYN END
			 , ORDERSNDDATE = CASE WHEN #{wkstatus}=#{sendWkstatus} THEN #{updatedate} ELSE ORDERSNDDATE END
			 , ORDERSNDUSERID = CASE WHEN #{wkstatus}=#{sendWkstatus} THEN #{updateurkey} ELSE ORDERSNDUSERID END
             , UPDATEDATE = #{updatedate}
             , UPDATEURKEY = #{updateurkey}
		 WHERE OWKEY = #{owkey}
		   AND SOHDKEY = #{sohdkey}		   
		   AND SOHDKEY IN (SELECT MAX(SOHDKEY)
		   					 FROM TORDER_INFO_SO_DT
		   					WHERE OWKEY = #{owkey}
							  AND SOHDKEY = #{sohdkey}
							  AND COALESCE(NISYN, 'N') != 'Y'
		   				   )

		/* oms-orderrest-sql-oracle.xml updateSoDtAfterEo */
		UPDATE TORDER_INFO_SO_DT 
		   SET WKSTATUS = #{wkstatus}
             , UPDATEDATE = #{updatedate}
             , UPDATEURKEY = #{updateurkey}
		 WHERE OWKEY = #{owkey}
		   AND SOHDKEY = #{sohdkey}
		   AND COALESCE(NISYN, 'N') != 'Y'

		/* oms-orderrest-sql-oracle.xml updateSoDtAutoComplete */
		UPDATE TORDER_INFO_SO_DT 
		   SET WKSTATUS = #{wkstatus}
		     , CNFRMQTY = EXPCTQTY
             , UPDATEDATE = #{updatedate}
             , UPDATEURKEY = #{updateurkey}
		 WHERE OWKEY = #{owkey}
		   AND SOHDKEY = #{sohdkey}

		/* oms-orderrest-sql-oracle.xml updateSoHdBatchStatus */
		UPDATE TORDER_INFO_SO_HD 
		   SET BATWKSTATUS = 'WAIT'
             , UPDATEDATE = #{updatedate}
             , UPDATEURKEY = #{updateurkey}
		 WHERE OWKEY = #{owkey}
		   AND SOHDKEY = #{sohdkey}


