     OWKEY
   , CTKEY
   , SOHDKEY
   , SODTKEY
   , RLESNO
   , EXPCTQTY
   , CNFRMQTY
   , NISCNLRNGDIV
   , ICKEY
   , UOM
   , CNFRMDATE
   , CLOSEYN
   , ORGORDERKEY
   , ORGORDERDTKEY
   , NISYN
   , DLVRYCORPCD
   , WBLNO
   , CNTRCD
   , MVOBGRPNO
   , WKTYPECD
   , CLAIMNO
   , RIRSNCD
   , CMT
   , AVQTY
   , NAVQTY
   , NORMALQTY
   , DMGQTY
   , DFCQTY
   , DONAQTY
   , FOODDMGQTY
   , MISOBQTY
   , REPROCESSYN
   , EXPIREDATE
   , DELIVERYPERSONID
   , ICADDYN
   , REQUESTDT
   , IFID
   , INSERTDATE
   , INSERTURKEY
   , UPDATEDATE
   , UPDATEURKEY
) VALUES (
     #{owkey}
   , #{ctkey}
   , #{sohdkey}
   , #{sodtkey}
   , #{rlesno}

   , #{cnfrmqty}


   , #{expctqty}

   , #{cnfrmqty}
   , #{niscnlrngdiv}
   , #{ickey}
   , COALESCE(#{uom}, 'EA')
   , #{cnfrmdate}
   , 'N' -- closeyn
   , #{orgorderkey}
   , #{orgorderdtkey}
   , #{nisyn}
   , #{dlvrycorpcd}
   , #{wblno}
   , #{cntrcd}
   , #{mvobgrpno}
   , #{wktypecd}
   , #{claimno}
   , #{rirsncd}
   , #{cmt}
   , COALESCE(#{avqty}, 0)
   , COALESCE(#{navqty}, 0)
   , COALESCE(#{normalqty}, 0)
   , COALESCE(#{dmgqty}, 0)
   , COALESCE(#{dfcqty}, 0)
   , COALESCE(#{donaqty}, 0)
   , COALESCE(#{fooddmgqty}, 0)
   , COALESCE(#{misobqty}, 0)
   , #{reprocessyn}
   , #{expiredate}
   , #{deliverypersonid}
   , #{icaddyn}
   , #{requestDt}
   , #{ifid}
   , TO_CHAR(CURRENT_TIMESTAMP,'YYYYMMDDHH24MISS')
   , #{interfaceUrkey}
   , TO_CHAR(CURRENT_TIMESTAMP,'YYYYMMDDHH24MISS')
   , #{interfaceUrkey}
)

