		/* oms-orderrest-sql-oracle.xml updateSapResultWmEo */
		UPDATE TORDER_INFO_WMS_PERFORMANCE
		   SET SAPSENDYN = 'Y'
		     , UPDATEDATE = #{interfaceDate}
		   	 , UPDATEURKEY = #{interfaceUrkey}
         WHERE OWKEY = #{owkey}
           AND SO_HDKEY = #{soHdkey}
		   AND SO_DTKEY = #{soDtkey}
		   AND DELYN = 'N'


		/* oms-orderrest-sql-oracle.xml updateSapResultTmEo */
		UPDATE TORDER_INFO_TMS_PERFORMANCE
		   SET SAPSENDYN = 'Y'
		     , UPDATEDATE = #{interfaceDate}
		   	 , UPDATEURKEY = #{interfaceUrkey}
         WHERE OWKEY = #{owkey}
           AND SO_HDKEY = #{soHdkey}
		   AND SO_DTKEY = #{soDtkey}
		   AND DELYN = 'N'


		/* oms-orderrest-sql-oracle.xml updateSapResultCoDt */
		UPDATE TORDER_INFO_CO_DT
		   SET WKSTATUS = #{wkstatus}
		     , UPDATEDATE = #{interfaceDate}
		   	 , UPDATEURKEY = #{interfaceUrkey}
         WHERE OWKEY = #{owkey}
           AND COHDKEY = #{cohdkey}
		   AND CODTKEY = #{codtkey}


		/* oms-orderrest-sql-oracle.xml updateSapResultCoHd */
		UPDATE TORDER_INFO_CO_HD
		   SET WKSTATUS = #{wkstatus}
		     , ERPSNDFAILYN = #{saptransfailyn}
		     , FAILCNT = CASE WHEN #{saptransfailyn}<>'Y' THEN 0 ELSE COALESCE(FAILCNT, 0)+1 END
		     , ERPSNDSEQ = CASE WHEN #{saptransfailyn}<>'Y' THEN (COALESCE(ERPSNDSEQ, '0')::INTEGER+1)::TEXT ELSE ERPSNDSEQ END
		     , ORDERRCMT = #{sapfailcomments} 
		     , UPDATEDATE = #{interfaceDate}
		   	 , UPDATEURKEY = #{interfaceUrkey}
         WHERE OWKEY = #{owkey}
           AND COHDKEY = #{cohdkey}


		/* oms-orderrest-sql-oracle.xml saveSaptransfailyn */
		UPDATE TORDER_INFO_CO_HD
		   SET ERPSNDFAILYN = #{erpsndfailyn}
		     , FAILCNT = 0
		     , UPDATEDATE = #{sysdate}
		   	 , UPDATEURKEY = #{surkey}
         WHERE OWKEY = #{owkey}
           AND COHDKEY = #{cohdkey}

		/* oms-orderrest-sql-oracle.xml updateIntfIbOrderErpStatus */
		UPDATE TORDER_EAI_IBORDER_BATCH
           SET SND_PROC_TYP = 'Y'
		 WHERE TRN_ID = #{trnId}

		/* oms-orderrest-sql-oracle.xml updateIntfB2bObOrderErpStatus */
		UPDATE TORDER_EAI_B2BOBORDER_BATCH
           SET SND_PROC_TYP = 'Y'
		 WHERE TRN_ID = #{trnId}
